import{_ as p,C as e,o as l,c as i,ag as a,E as t}from"./chunks/framework.CAXxHpAX.js";const r="/images/chapter-05.svg",_=JSON.parse('{"title":"5. 数据仓库建模：从表设计到分析建模","description":"把业务表重构成事实表、维度表、分层模型和稳定指标体系。","frontmatter":{"title":"5. 数据仓库建模：从表设计到分析建模","description":"把业务表重构成事实表、维度表、分层模型和稳定指标体系。","prev":{"text":"4. OLTP vs OLAP：大数据系统的第一分水岭","link":"/chapters/04-oltp-olap"},"next":{"text":"6. ETL / ELT：数据如何进入大数据系统","link":"/chapters/06-etl-elt"}},"headers":[],"relativePath":"chapters/05-data-warehouse-modeling.md","filePath":"chapters/05-data-warehouse-modeling.md"}'),d={name:"chapters/05-data-warehouse-modeling.md"};function c(b,s,o,u,h,m){const n=e("Mermaid");return l(),i("div",null,[s[0]||(s[0]=a('<h1 id="_5-数据仓库建模-从表设计到分析建模" tabindex="-1">5. 数据仓库建模：从表设计到分析建模 <a class="header-anchor" href="#_5-数据仓库建模-从表设计到分析建模" aria-label="Permalink to &quot;5. 数据仓库建模：从表设计到分析建模&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">本章导读</p><p>把业务表重构成事实表、维度表、分层模型和稳定指标体系。</p></div><p><img src="'+r+'" alt="数据仓库建模：从表设计到分析建模"></p><h2 id="本章阅读框架" tabindex="-1">本章阅读框架 <a class="header-anchor" href="#本章阅读框架" aria-label="Permalink to &quot;本章阅读框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阅读问题</th><th>本章回答方式</th></tr></thead><tbody><tr><td>这个问题为什么出现？</td><td>从业务增长、数据规模、系统目标或 AI 应用压力切入。</td></tr><tr><td>它解决什么问题？</td><td>提炼为一个核心判断，避免把概念写成孤立定义。</td></tr><tr><td>它不解决什么问题？</td><td>在机制解释和常见误区中说明边界，防止工具崇拜。</td></tr><tr><td>它在真实平台哪里出现？</td><td>放回 PostgreSQL、数仓、批流、OLAP、湖仓、向量、图和治理的演化链路。</td></tr><tr><td>读完要会做什么？</td><td>通过场景案例和实战任务转成可练习的判断。</td></tr></tbody></table>',5)),t(n,{code:"flowchart%20LR%0A%20%20A%5B%22PostgreSQL%20%E6%BA%90%E8%A1%A8%22%5D%20--%3E%20ODS%5B%22ODS%20%E5%8E%9F%E5%A7%8B%E5%B1%82%22%5D%0A%20%20ODS%20--%3E%20DWD%5B%22DWD%20%E6%98%8E%E7%BB%86%E5%B1%82%22%5D%0A%20%20DWD%20--%3E%20DWS%5B%22DWS%20%E6%B1%87%E6%80%BB%E5%B1%82%22%5D%0A%20%20DWS%20--%3E%20ADS%5B%22ADS%20%E5%BA%94%E7%94%A8%E5%B1%82%22%5D%0A%20%20DWD%20--%3E%20F%5B%22%E4%BA%8B%E5%AE%9E%E8%A1%A8%22%5D%0A%20%20DWD%20--%3E%20DIM%5B%22%E7%BB%B4%E5%BA%A6%E8%A1%A8%22%5D%0A"}),s[1]||(s[1]=a(`<p>业务库设计关注业务正确。</p><p>数仓设计关注分析效率、指标口径和数据复用。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>第 4 章说明了为什么业务交易和分析计算要分工。但把数据从 PostgreSQL 同步到另一个系统，并不自动得到一个可用的数据仓库。</p><p>如果只是把业务库表原样复制一份，分析团队很快会遇到新问题：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders 表一行是一笔订单，order_items 一行是订单商品明细，GMV 应该从哪张表算？</span></span>
<span class="line"><span>支付成功时间、订单创建时间、发货时间都存在，日报应该按哪个时间统计？</span></span>
<span class="line"><span>用户等级会变化，历史订单应该看当时等级还是当前等级？</span></span>
<span class="line"><span>运营、财务、增长团队都写 GMV，为什么结果不一样？</span></span>
<span class="line"><span>一个报表字段出错时，怎样知道它来自哪个源表和哪条任务？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这些问题不是查询引擎能单独解决的。ClickHouse、Spark、Trino 可以让查询更快，但不会自动告诉你业务过程、分析粒度、指标口径和数据责任应该如何设计。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><p>数仓不是复制业务库，而是把业务系统中的对象、事件和关系重构成可分析的数据语义。</p><blockquote><p>数仓建模的核心，不是多建几层表，而是让业务过程、分析粒度、指标口径和数据责任变得清晰。</p></blockquote><p>本章要建立的判断是：数仓建模解决的是分析语义问题。它把 OLTP 中为了业务正确而设计的表，重构成面向分析复用的事实、维度、分层、汇总和指标体系。</p><p>数仓建模也不是万能的。它不能替代源系统正确性，不能让错误数据自动变正确，不能省掉 ETL/ELT、调度、质量校验和权限治理。它负责把数据进入分析系统之后的组织方式设计清楚。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="_5-1-数仓基础概念" tabindex="-1">5.1 数仓基础概念 <a class="header-anchor" href="#_5-1-数仓基础概念" aria-label="Permalink to &quot;5.1 数仓基础概念&quot;">​</a></h3><p>数据仓库是面向分析的数据系统。</p><p>它接收来自业务库、日志系统、外部数据源的数据，经过清洗、转换、建模和汇总，服务 BI、指标、报表、运营分析、机器学习和 AI 应用。</p><p>几个核心概念必须先建立。</p><p>Fact Table 是事实表，记录业务过程中的事实，例如订单事实、支付事实、浏览事实。</p><p>Dimension Table 是维度表，描述事实相关的业务对象，例如用户维度、商品维度、时间维度、渠道维度。</p><p>Metric 是指标，例如 GMV、订单数、客单价、留存率。</p><p>Dimension 是观察指标的角度，例如日期、地区、渠道、商品类目。</p><p>Granularity 是粒度，回答一行数据代表什么。</p><p>Lineage 是血缘，回答数据从哪里来、经过哪些任务、影响哪些下游。</p><p>Data Quality 是质量，回答数据是否完整、准确、一致、及时。</p><p>这些概念不能作为孤立名词记忆。它们都围绕一个核心问题：如何让同一批业务事实，在多个团队、多个报表、多个应用中被稳定复用。</p><h3 id="_5-2-数仓分层" tabindex="-1">5.2 数仓分层 <a class="header-anchor" href="#_5-2-数仓分层" aria-label="Permalink to &quot;5.2 数仓分层&quot;">​</a></h3><p>常见数仓分层包括：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ODS -&gt; DWD -&gt; DWS -&gt; ADS</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>ODS 是原始数据层，尽量保留源系统数据形态，承接 PostgreSQL、MySQL、日志、外部文件等数据。</p><p>DWD 是明细数据层，对原始数据做清洗、标准化、去重、字段规范和业务过程整理。</p><p>DWS 是汇总数据层，按主题和维度生成可复用的汇总数据，例如用户日汇总、商品日汇总、订单日汇总。</p><p>ADS 是应用数据层，面向具体报表、看板、指标服务或业务应用。</p><p>分层的核心判断是：</p><blockquote><p>数仓分层不是为了制造复杂目录，而是为了把原始数据、明细事实、公共汇总和应用结果分开管理。</p></blockquote><p>没有分层，所有任务直接从源表加工到报表，很快会变成脚本堆叠：口径重复、依赖混乱、难以复用、难以追踪。</p><h3 id="_5-3-建模方法" tabindex="-1">5.3 建模方法 <a class="header-anchor" href="#_5-3-建模方法" aria-label="Permalink to &quot;5.3 建模方法&quot;">​</a></h3><p>常见建模方法包括星型模型、雪花模型、宽表模型、维度建模、Data Vault、One Big Table。</p><p>初学阶段最重要的是理解维度建模。</p><p>以订单分析为例，事实表可以是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>fact_order</span></span>
<span class="line"><span>├── order_id</span></span>
<span class="line"><span>├── user_id</span></span>
<span class="line"><span>├── product_id</span></span>
<span class="line"><span>├── date_id</span></span>
<span class="line"><span>├── channel_id</span></span>
<span class="line"><span>├── order_amount</span></span>
<span class="line"><span>└── order_status</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>维度表可以是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dim_user</span></span>
<span class="line"><span>dim_product</span></span>
<span class="line"><span>dim_date</span></span>
<span class="line"><span>dim_channel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>星型模型的特点是：事实表在中心，维度表围绕事实表。</p><p>它解决的是分析可读性和查询效率问题。</p><p>雪花模型会进一步规范化维度，例如商品维度拆出类目维度、品牌维度。它降低冗余，但查询更复杂。</p><p>宽表则把常用维度直接冗余到事实或汇总表中，提高查询便利性，但增加存储和口径维护成本。</p><p>建模没有绝对标准，关键是围绕分析任务做取舍。</p><h3 id="_5-4-事实表" tabindex="-1">5.4 事实表 <a class="header-anchor" href="#_5-4-事实表" aria-label="Permalink to &quot;5.4 事实表&quot;">​</a></h3><p>事实表记录业务过程。</p><p>常见事实表有三类。</p><p>事务事实表记录每一次业务事件，例如一笔订单、一笔支付、一次点击。</p><p>周期快照事实表按固定周期记录状态，例如每日库存、每日账户余额、每日用户活跃状态。</p><p>累积快照事实表记录一个业务流程从开始到结束的关键节点，例如订单从创建、支付、发货、签收到退款的过程。</p><p>事实表最重要的问题是粒度。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一行是一笔订单？</span></span>
<span class="line"><span>一行是订单中的一个商品？</span></span>
<span class="line"><span>一行是一次支付尝试？</span></span>
<span class="line"><span>一行是用户某天的活跃状态？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>粒度决定了指标如何计算，也决定了 JOIN 是否会放大数据。</p><h3 id="_5-5-维度表" tabindex="-1">5.5 维度表 <a class="header-anchor" href="#_5-5-维度表" aria-label="Permalink to &quot;5.5 维度表&quot;">​</a></h3><p>维度表描述业务对象。</p><p>常见维度包括：</p><ul><li>用户维度。</li><li>商品维度。</li><li>时间维度。</li><li>地域维度。</li><li>渠道维度。</li><li>设备维度。</li></ul><p>维度表解决的是“按什么角度看事实”的问题。</p><p>例如 GMV 可以按日期看、按商品类目看、按渠道看、按地区看、按用户等级看。每个观察角度都依赖维度。</p><p>维度表还会遇到缓慢变化维 SCD。</p><p>例如用户等级会变化，商品类目会调整，组织架构会变更。数仓需要决定：历史订单分析时使用当时的用户等级，还是当前的用户等级？</p><p>这不是技术细节，而是分析语义问题。</p><h3 id="_5-6-指标体系" tabindex="-1">5.6 指标体系 <a class="header-anchor" href="#_5-6-指标体系" aria-label="Permalink to &quot;5.6 指标体系&quot;">​</a></h3><p>指标体系解决的是口径一致问题。</p><p>如果每个团队都自己写 GMV：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>有人按创建时间统计</span></span>
<span class="line"><span>有人按支付时间统计</span></span>
<span class="line"><span>有人包含退款</span></span>
<span class="line"><span>有人排除退款</span></span>
<span class="line"><span>有人包含测试订单</span></span>
<span class="line"><span>有人排除测试订单</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>最后看板上的 GMV 就会互相冲突。</p><p>指标通常分为：</p><ul><li>原子指标：来自明细事实的基础度量，例如支付金额、订单数。</li><li>派生指标：在原子指标上增加时间、维度、过滤条件，例如日支付 GMV。</li><li>复合指标：由多个指标计算得到，例如客单价、转化率、留存率。</li></ul><p>一个合格指标至少要说明：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>指标名称</span></span>
<span class="line"><span>业务含义</span></span>
<span class="line"><span>统计对象</span></span>
<span class="line"><span>计算公式</span></span>
<span class="line"><span>时间口径</span></span>
<span class="line"><span>过滤规则</span></span>
<span class="line"><span>维度范围</span></span>
<span class="line"><span>负责人</span></span>
<span class="line"><span>数据血缘</span></span>
<span class="line"><span>版本</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>指标体系的核心判断是：</p><blockquote><p>指标不是 SQL 结果，而是业务共识、计算逻辑和数据责任的结合。</p></blockquote><h3 id="深度展开-数据仓库建模如何落到真实系统" tabindex="-1">深度展开：数据仓库建模如何落到真实系统 <a class="header-anchor" href="#深度展开-数据仓库建模如何落到真实系统" aria-label="Permalink to &quot;深度展开：数据仓库建模如何落到真实系统&quot;">​</a></h3><p>本节补齐本章的工程细节。阅读时不要只记住概念名称，而要把它放回“输入是什么、处理路径是什么、输出给谁、边界在哪里、如何验证”的链路中。</p><h4 id="一、它从什么问题开始" tabindex="-1">一、它从什么问题开始 <a class="header-anchor" href="#一、它从什么问题开始" aria-label="Permalink to &quot;一、它从什么问题开始&quot;">​</a></h4><p>业务库表结构服务写入正确性，不天然服务分析复用。分析系统需要把业务事实重构成可理解、可复用、可治理的模型。</p><p>这个问题通常不会以技术名词出现，而是以业务现象出现：报表变慢、指标不一致、实时看板延迟、RAG 召回不稳定、数据无法追溯、项目 Demo 无法验收。能不能把现象还原成系统问题，是本书要训练的第一层能力。</p><h4 id="二、输入数据和前置判断" tabindex="-1">二、输入数据和前置判断 <a class="header-anchor" href="#二、输入数据和前置判断" aria-label="Permalink to &quot;二、输入数据和前置判断&quot;">​</a></h4><p>输入是业务源表、事件流、维度属性、指标定义、组织口径和历史变更规则。</p><p>在动手之前，至少要确认四件事：</p><table tabindex="0"><thead><tr><th>判断项</th><th>要回答的问题</th></tr></thead><tbody><tr><td>数据粒度</td><td>一行代表什么事实，是用户、订单、订单明细、事件、文件、Chunk，还是一条关系？</td></tr><tr><td>时间边界</td><td>使用创建时间、更新时间、支付时间、事件时间，还是处理时间？</td></tr><tr><td>状态边界</td><td>哪些状态算有效，哪些测试、取消、退款、重复或迟到数据要排除？</td></tr><tr><td>责任边界</td><td>这个环节负责记录事实、生产指标、加速查询、治理质量，还是服务 AI 应用？</td></tr></tbody></table><h4 id="三、处理路径" tabindex="-1">三、处理路径 <a class="header-anchor" href="#三、处理路径" aria-label="Permalink to &quot;三、处理路径&quot;">​</a></h4><p>处理路径是从 ODS 保留原始数据开始，在 DWD 建立明细事实和维度，在 DWS 沉淀主题汇总，在 ADS 面向报表、运营和应用输出数据集。</p><p>这条路径应该能被写成可执行流程，而不是停留在术语解释。一个合格的设计至少要说明：数据从哪里来、经过哪些转换、写到哪里、谁消费、失败后如何重跑、结果如何校验。</p><h4 id="四、在真实平台中的位置" tabindex="-1">四、在真实平台中的位置 <a class="header-anchor" href="#四、在真实平台中的位置" aria-label="Permalink to &quot;四、在真实平台中的位置&quot;">​</a></h4><p>在真实平台里，数仓建模连接业务库和分析消费层。它让 Spark、Hive、Trino、ClickHouse、Doris、BI 和 AI 应用读到同一套语义，而不是各自重新解释业务表。</p><p>平台位置决定了它和前后系统的关系。不要孤立地问“这个技术好不好”，而要问：</p><ul><li>它继承了上一层什么问题？</li><li>它把什么复杂度转移给了下一层？</li><li>它的输出是否能被复用、追溯和治理？</li><li>它是否改变了数据粒度、延迟、一致性或权限边界？</li></ul><h4 id="五、边界和失败模式" tabindex="-1">五、边界和失败模式 <a class="header-anchor" href="#五、边界和失败模式" aria-label="Permalink to &quot;五、边界和失败模式&quot;">​</a></h4><p>数仓建模不等于复制业务库，也不等于把所有表做成宽表。模型过细会难以使用，模型过宽会难以维护；没有指标治理的建模仍会产生口径漂移。</p><p>常见失败信号可以这样检查：</p><table tabindex="0"><thead><tr><th>失败信号</th><th>应该追问什么</th></tr></thead><tbody><tr><td>报表都在重复 JOIN 源表</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>每个团队维护自己的 GMV 口径</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>维度属性变化导致历史结果不可解释</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>明细表、汇总表和应用表边界混乱</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr></tbody></table><h4 id="六、可操作练习" tabindex="-1">六、可操作练习 <a class="header-anchor" href="#六、可操作练习" aria-label="Permalink to &quot;六、可操作练习&quot;">​</a></h4><p>把订单、订单明细、商品、用户、支付表设计成事实表、维度表和每日指标汇总表，并写出粒度、主键、更新方式和质量检查。</p><p>练习完成后不要只看“有没有跑通”，还要补一份复盘：</p><ul><li>输入数据是否足以支撑问题？</li><li>口径和边界是否写清楚？</li><li>结果能否被重复计算和对账？</li><li>如果数据量扩大 10 倍，瓶颈会出现在哪里？</li><li>如果接入下游 BI、RAG 或治理系统，还缺哪些元数据？</li></ul><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><p>本章承接第 4 章的 OLTP/OLAP 分工。</p><p>第 4 章解决的是“分析负载应该从业务库中分离出去”。第 5 章进一步回答：数据离开 PostgreSQL 后，不能只是换个地方存，还必须重新组织成分析模型。</p><p>数仓建模位于以下链路中间：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL / MySQL 业务事实</span></span>
<span class="line"><span>  -&gt; ETL / CDC 同步</span></span>
<span class="line"><span>  -&gt; ODS 原始层</span></span>
<span class="line"><span>  -&gt; DWD 明细事实与维度</span></span>
<span class="line"><span>  -&gt; DWS 公共汇总</span></span>
<span class="line"><span>  -&gt; ADS 应用数据</span></span>
<span class="line"><span>  -&gt; BI / 指标服务 / 机器学习 / AI 应用</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>它向前依赖源系统的业务事实，向后支撑 OLAP 查询、批处理、实时指标、湖仓、特征工程和 AI 数据应用。如果这里没有明确粒度、维度和指标口径，后续再快的查询引擎也只会更快地产生不一致结果。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><h3 id="七、从-postgresql-业务表到数仓模型" tabindex="-1">七、从 PostgreSQL 业务表到数仓模型 <a class="header-anchor" href="#七、从-postgresql-业务表到数仓模型" aria-label="Permalink to &quot;七、从 PostgreSQL 业务表到数仓模型&quot;">​</a></h3><p>假设源系统有：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>users</span></span>
<span class="line"><span>products</span></span>
<span class="line"><span>orders</span></span>
<span class="line"><span>order_items</span></span>
<span class="line"><span>payments</span></span>
<span class="line"><span>events</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>数仓不应该简单复制这些表就结束。</p><p>它要重构为分析模型：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ODS</span></span>
<span class="line"><span>  -&gt; ods_users</span></span>
<span class="line"><span>  -&gt; ods_orders</span></span>
<span class="line"><span>  -&gt; ods_order_items</span></span>
<span class="line"><span>  -&gt; ods_payments</span></span>
<span class="line"><span>  -&gt; ods_events</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DWD</span></span>
<span class="line"><span>  -&gt; dwd_order_detail</span></span>
<span class="line"><span>  -&gt; dwd_payment_detail</span></span>
<span class="line"><span>  -&gt; dwd_user_event_detail</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DWS</span></span>
<span class="line"><span>  -&gt; dws_user_daily</span></span>
<span class="line"><span>  -&gt; dws_product_daily</span></span>
<span class="line"><span>  -&gt; dws_order_daily</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ADS</span></span>
<span class="line"><span>  -&gt; ads_sales_dashboard</span></span>
<span class="line"><span>  -&gt; ads_retention_report</span></span>
<span class="line"><span>  -&gt; ads_conversion_funnel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br></div></div><p>这就是从业务库建模到分析建模的迁移。</p><p>以 GMV 看板为例，业务库中的 <code>orders</code> 表只记录订单主信息，<code>order_items</code> 记录商品明细，<code>payments</code> 记录支付事实。数仓建模时可以这样拆：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ODS</span></span>
<span class="line"><span>  ods_orders                原样接入订单主表</span></span>
<span class="line"><span>  ods_order_items           原样接入订单商品明细</span></span>
<span class="line"><span>  ods_payments              原样接入支付记录</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DWD</span></span>
<span class="line"><span>  dwd_order_payment_detail  对齐订单、明细、支付状态，形成支付口径明细</span></span>
<span class="line"><span></span></span>
<span class="line"><span>DWS</span></span>
<span class="line"><span>  dws_sales_daily           按日期、类目、渠道形成公共日汇总</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ADS</span></span>
<span class="line"><span>  ads_sales_dashboard       面向经营看板的展示表</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>这里最重要的不是表名，而是每层责任：</p><ul><li>ODS 保留源系统形态，便于追溯。</li><li>DWD 形成稳定明细事实，明确一行代表什么。</li><li>DWS 把高频复用指标沉淀为公共汇总。</li><li>ADS 面向具体看板和应用，不反向污染公共层口径。</li></ul><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：数仓就是把业务库同步一份。</strong></p><p>同步只是入口。数仓真正的价值在于清洗、建模、分层、汇总、治理和口径统一。</p><p><strong>误区二：分层越多越专业。</strong></p><p>分层要服务复用和治理。没有明确作用的分层只会增加任务链路和维护成本。</p><p><strong>误区三：宽表能解决所有问题。</strong></p><p>宽表查询方便，但会带来冗余、更新困难、口径固化和存储成本。它适合高频应用场景，不适合替代全部建模。</p><p><strong>误区四：指标就是 SQL。</strong></p><p>SQL 是计算方式，指标还包括业务定义、口径、负责人、版本、血缘和质量要求。</p><p><strong>误区五：ODS、DWD、DWS、ADS 是固定模板。</strong></p><p>分层名称可以不同，关键是责任边界。小团队可以减少层数，大平台可以增加主题域和数据集市，但不能丢掉原始追溯、明细复用、公共汇总和应用隔离这些基本问题。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>基于电商业务表，设计一个最小数仓模型。</p><p>要求：</p><ol><li>设计 ODS 层源表映射。</li><li>设计一个订单明细事实表。</li><li>设计用户、商品、日期三个维度表。</li><li>定义 GMV、订单数、客单价三个指标。</li><li>说明每个指标的时间口径和过滤规则。</li><li>设计一个面向经营看板的 ADS 表。</li></ol><p>复盘问题：</p><ul><li>哪些数据保持源系统原样？</li><li>哪些数据被清洗和标准化？</li><li>哪些表可以复用？</li><li>哪些指标需要负责人确认？</li><li>哪些字段需要质量校验？</li></ul><p>进阶任务：为 GMV 写一份指标定义卡。</p><p>至少包含：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>指标名称：支付 GMV</span></span>
<span class="line"><span>业务含义：用户成功支付订单产生的交易金额</span></span>
<span class="line"><span>统计对象：支付成功的订单明细</span></span>
<span class="line"><span>计算公式：SUM(payment_amount 或 item_amount，按确认口径选择)</span></span>
<span class="line"><span>时间口径：支付成功时间</span></span>
<span class="line"><span>过滤规则：排除未支付、取消、测试、风控拦截订单</span></span>
<span class="line"><span>维度范围：日期、渠道、商品类目、用户等级、地区</span></span>
<span class="line"><span>负责人：经营分析负责人</span></span>
<span class="line"><span>数据血缘：orders / order_items / payments -&gt; dwd_order_payment_detail -&gt; dws_sales_daily</span></span>
<span class="line"><span>质量规则：支付金额非负、订单支付状态一致、明细金额与订单金额可对账</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>复盘时回答：这个指标如果被用于财务报表、运营看板和推荐系统特征，哪些字段和质量规则必须更加严格？</p><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>数仓建模把业务库中的数据重新组织成分析语义。</p><p>PostgreSQL 业务表关注业务正确，数仓模型关注分析效率、指标口径和跨团队复用。</p><p>下一章进入 ETL / ELT。</p><p>因为模型设计出来之后，必须回答一个工程问题：数据如何从 PostgreSQL 进入数仓，并在持续变化中保持可用、可信、可追踪？</p>`,144))])}const v=p(d,[["render",c]]);export{_ as __pageData,v as default};
